-- ----------------------------
-- Table structure for mdc_file
-- ----------------------------
DROP TABLE IF EXISTS `mdc_file`;
CREATE TABLE `mdc_file` (
  `id` bigint NOT NULL COMMENT 'ID',
  `object_id` bigint DEFAULT NULL COMMENT '业务id',
  `object_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '对象类型',
  `file_type` int DEFAULT '1' COMMENT '文件类型',
  `url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件访问地址',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小\n单位字节',
  `filename` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件名称',
  `original_filename` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '原始文件名',
  `bucket` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '桶',
  `base_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '基础存储路径',
  `path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '存储路径',
  `ext` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件扩展名',
  `content_type` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'MIME类型',
  `platform` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '存储平台',
  `th_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '缩略图访问路径',
  `th_filename` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '缩略图名称',
  `th_size` bigint DEFAULT NULL COMMENT '缩略图大小\n单位字节',
  `th_content_type` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '缩略图MIME类型',
  `metadata` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '文件元数据',
  `user_metadata` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '文件用户元数据',
  `th_metadata` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '缩略图元数据',
  `th_user_metadata` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '缩略图用户元数据',
  `attr` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '附加属性',
  `file_acl` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件ACL',
  `th_file_acl` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '缩略图文件ACL',
  `hash_info` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '哈希信息',
  `upload_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '上传ID\n仅在手动分片上传时使用',
  `upload_status` int DEFAULT NULL COMMENT '上传状态\n仅在手动分片上传时使用，1：初始化完成，2：上传完成',
  `created_at` datetime NOT NULL COMMENT '创建时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `updated_at` datetime NOT NULL COMMENT '最后修改时间',
  `updated_by` bigint DEFAULT NULL COMMENT '最后修改人',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='文件';

-- ----------------------------
-- Records of mdc_file
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for mdc_file_part
-- ----------------------------
DROP TABLE IF EXISTS `mdc_file_part`;
CREATE TABLE `mdc_file_part` (
  `id` bigint NOT NULL COMMENT '分片id',
  `platform` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '存储平台',
  `upload_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '上传ID，仅在手动分片上传时使用',
  `e_tag` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分片 ETag',
  `part_number` int DEFAULT NULL COMMENT '分片号。每一个上传的分片都有一个分片号，一般情况下取值范围是1~10000',
  `part_size` bigint DEFAULT NULL COMMENT '文件大小，单位字节',
  `hash_info` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '哈希信息',
  `created_at` datetime NOT NULL COMMENT '创建时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `updated_at` datetime NOT NULL COMMENT '最后修改时间',
  `updated_by` bigint DEFAULT NULL COMMENT '最后修改人',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='文件分片\n仅在手动分片上传时使用';

-- ----------------------------
-- Records of mdc_file_part
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for mdc_interface_config
-- ----------------------------
DROP TABLE IF EXISTS `mdc_interface_config`;
CREATE TABLE `mdc_interface_config` (
  `id` bigint NOT NULL COMMENT 'ID',
  `key` varchar(255) NOT NULL COMMENT '接口标识',
  `name` varchar(255) NOT NULL COMMENT '接口名称',
  `msg_type` smallint NOT NULL DEFAULT '2' COMMENT '接口类型\n[1-站内信 2-短信 3-邮件]',
  `exec_mode` smallint NOT NULL DEFAULT '1' COMMENT '执行方式\n[1-实现类 2-脚本 3-magic-api]',
  `script` text COMMENT '实现脚本',
  `impl_class` varchar(255) DEFAULT NULL COMMENT '实现类',
  `magic_api_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '实现ID',
  `config_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '配置参数\n(JSON存储：AppId, SecretKey等)',
  `state` bit(1) NOT NULL DEFAULT b'1' COMMENT '状态',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `updated_at` datetime(3) DEFAULT NULL COMMENT '修改时间',
  `updated_by` bigint DEFAULT NULL COMMENT '修改人',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_key` (`key`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='接口';

