-- ----------------------------
-- Table structure for mdc_interface_log
-- ----------------------------
DROP TABLE IF EXISTS `mdc_interface_log`;
CREATE TABLE `mdc_interface_log` (
  `id` bigint NOT NULL COMMENT 'id',
  `msg_task_id` bigint DEFAULT NULL COMMENT '任务ID',
  `interface_stat_id` bigint NOT NULL COMMENT '接口ID',
  `exec_start_time` datetime(3) NOT NULL COMMENT '执行开始时间',
  `exec_end_time` datetime(3) DEFAULT NULL COMMENT '执行结束时间',
  `status` smallint DEFAULT '1' COMMENT '执行状态\n[1-初始化 2-成功 3-失败]',
  `param` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '请求参数',
  `result` longtext COMMENT '接口返回',
  `error_msg` longtext COMMENT '异常信息',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `updated_at` datetime(3) DEFAULT NULL COMMENT '修改时间',
  `updated_by` bigint DEFAULT NULL COMMENT '修改人',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='接口执行日志记录';

-- ----------------------------
-- Records of mdc_interface_log
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
