-- ----------------------------
-- Table structure for mdc_request_log
-- ----------------------------
DROP TABLE IF EXISTS `mdc_request_log`;
CREATE TABLE `mdc_request_log` (
  `id` bigint NOT NULL COMMENT '主键',
  `ip_address` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT 'IP地址',
  `abnormal` bit(1) DEFAULT b'0' COMMENT '是否异常',
  `log_type` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '1' COMMENT '日志类型\n[1-查询 2-新增 3-修改 4-删除 9-其他]',
  `user_id` bigint DEFAULT NULL COMMENT '用户id',
  `user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '操作人',
  `class_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '类路径',
  `method_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '方法名',
  `http_uri` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '请求地址',
  `http_method` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'GET' COMMENT '请求类型\n#HttpMethod{GET:GET请求;POST:POST请求;PUT:PUT请求;DELETE:DELETE请求;PATCH:PATCH请求;TRACE:TRACE请求;HEAD:HEAD请求;OPTIONS:OPTIONS请求;}',
  `http_param` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `http_response` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '返回值',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '操作描述',
  `ex_info` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '异常日志',
  `start_time` datetime(3) DEFAULT NULL COMMENT '开始时间',
  `finish_time` datetime(3) DEFAULT NULL COMMENT '完成时间',
  `consuming_time` bigint DEFAULT '0' COMMENT '消耗时间',
  `ua` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '浏览器',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='请求日志';

-- ----------------------------
-- Records of mdc_request_log
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for mdc_request_log_detail
-- ----------------------------
DROP TABLE IF EXISTS `mdc_request_log_detail`;
CREATE TABLE `mdc_request_log_detail` (
  `id` bigint NOT NULL COMMENT '主键',
  `request_body` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `response_body` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '返回值',
  `exception_stack` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '异常堆栈',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='请求日志';

-- ----------------------------
-- Records of mdc_request_log_detail
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for mdc_resource_button
-- ----------------------------
DROP TABLE IF EXISTS `mdc_resource_button`;
CREATE TABLE `mdc_resource_button` (
  `id` bigint NOT NULL COMMENT 'ID',
  `menu_id` bigint NOT NULL COMMENT '所属菜单',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '编码\n唯一编码，用于区分资源',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '名称',
  `icon` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '图标',
  `show_mode` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '显示方式\n [01-文字 02-图标 03-文字和图标]',
  `btn_type` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '按钮类型 \n[01-default 02-primary 03-info 04-success 05-warning 06-error]',
  `state` bit(1) NOT NULL DEFAULT b'1' COMMENT '状态\n[0-禁用 1-启用]',
  `created_by` bigint DEFAULT NULL COMMENT '创建人id',
  `created_at` datetime(3) NOT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人id',
  `updated_at` datetime(3) NOT NULL COMMENT '更新时间',
  `deleted_by` bigint DEFAULT NULL COMMENT '删除人',
  `deleted_at` bigint NOT NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_resource_code` (`code`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='按钮';

