COMMIT;

-- ----------------------------
-- Table structure for mdc_resource_data_perm
-- ----------------------------
DROP TABLE IF EXISTS `mdc_resource_data_perm`;
CREATE TABLE `mdc_resource_data_perm` (
  `id` bigint NOT NULL COMMENT 'ID',
  `menu_id` bigint NOT NULL COMMENT '所属菜单',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '编码\n唯一编码，用于区分资源',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '名称',
  `state` bit(1) NOT NULL DEFAULT b'1' COMMENT '状态\n[0-禁用 1-启用]',
  `is_def` bit(1) NOT NULL DEFAULT b'0' COMMENT '默认权限',
  `data_scope` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '数据范围\n[01-全部 02-本单位及子级 03-本单位 04-本部门及子级 05-本部门 06-个人 07-自定义]',
  `custom_class` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '实现类',
  `weight` int DEFAULT '1' COMMENT '顺序号',
  `created_by` bigint DEFAULT NULL COMMENT '创建人id',
  `created_at` datetime(3) NOT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人id',
  `updated_at` datetime(3) NOT NULL COMMENT '更新时间',
  `deleted_by` bigint DEFAULT NULL COMMENT '删除人',
  `deleted_at` bigint NOT NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_resource_code` (`code`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='数据权限';

