-- ----------------------------
-- Table structure for mdc_resource_uri
-- ----------------------------
DROP TABLE IF EXISTS `mdc_resource_uri`;
CREATE TABLE `mdc_resource_uri` (
  `id` bigint NOT NULL COMMENT 'ID',
  `menu_id` bigint NOT NULL COMMENT '所属菜单',
  `application_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '所属应用',
  `controller` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '类名',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '接口名',
  `uri` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '接口地址',
  `request_method` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '请求方式',
  `is_input` bit(1) DEFAULT b'0' COMMENT '手动录入',
  `created_by` bigint DEFAULT NULL COMMENT '创建人id',
  `created_at` datetime(3) NOT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_resource_code` (`controller`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='接口权限';

-- ----------------------------
-- Records of mdc_resource_uri
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for mdc_role
-- ----------------------------
DROP TABLE IF EXISTS `mdc_role`;
CREATE TABLE `mdc_role` (
  `id` bigint NOT NULL COMMENT 'ID',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '角色编码',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '角色名称',
  `role_category` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '10' COMMENT '角色分类\n[10-普通角色 20-管理员角色 30-权限集合]',
  `role_type` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '10' COMMENT '角色类型\n[10-功能角色 20-桌面角色 30-数据角色]',
  `org_nature` int DEFAULT '1' COMMENT '组织性质\n[1-默认 90-开发者 99-运维]',
  `template_role` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否模版',
  `remarks` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '说明',
  `state` bit(1) NOT NULL DEFAULT b'0' COMMENT '状态\n[0-禁用 1-启用]',
  `created_by` bigint DEFAULT NULL COMMENT '创建人id',
  `created_at` datetime(3) NOT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人id',
  `updated_at` datetime(3) NOT NULL COMMENT '更新时间',
  `deleted_by` bigint DEFAULT NULL COMMENT '删除人',
  `deleted_at` bigint NOT NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code_delete` (`role_category`,`code`,`deleted_by`) USING BTREE,
  KEY `idx_id_state` (`id`,`state`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='角色';

-- ----------------------------
-- Records of mdc_role
-- ----------------------------
BEGIN;
INSERT INTO `mdc_role` (`id`, `code`, `name`, `role_category`, `role_type`, `org_nature`, `template_role`, `remarks`, `state`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES (29685645719521280, 'OPERATIONS_ADMIN_COLL', '运维管理员权限集', '30', '10', 99, b'1', '用于配置 内置的运维管理员 能分配什么权限。', b'1', 680083598598475778, '2025-12-03 23:55:56.347', 680083598598475778, '2026-02-06 10:45:57.831', NULL, 0);
