-- ----------------------------
-- Table structure for mdc_user
-- ----------------------------
DROP TABLE IF EXISTS `mdc_user`;
CREATE TABLE `mdc_user` (
  `id` bigint NOT NULL COMMENT 'ID',
  `username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户名',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '密码',
  `sex` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '性别\n[0-男 1-女]',
  `salt` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '盐值',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '电话号码',
  `avatar` bigint DEFAULT NULL COMMENT '头像',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '姓名',
  `email` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '邮箱地址',
  `state` bit(1) DEFAULT b'1' COMMENT '状态\n[0-禁用 1-正常]',
  `last_dept_id` bigint DEFAULT NULL COMMENT '上次登录的部门',
  `last_company_id` bigint DEFAULT NULL COMMENT '上次登录的单位',
  `last_top_company_id` bigint DEFAULT NULL COMMENT '上次登录的顶级单位',
  `pw_error_last_time` datetime(3) DEFAULT NULL COMMENT '输错密码时间',
  `pw_error_num` int DEFAULT '0' COMMENT '密码错误次数',
  `pw_expire_time` datetime(3) DEFAULT NULL COMMENT '密码过期时间',
  `last_login_time` datetime(3) DEFAULT NULL COMMENT '最后登录时间',
  `wx_openid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信登录openId',
  `dd_openid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '钉钉openId',
  `user_type` int DEFAULT '1' COMMENT '人员类型\r\n[1-普通用户 2-管理员 90-开发者 99-运维管理员]',
  `position_id` bigint DEFAULT NULL COMMENT '所属岗位',
  `user_source` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'ua' COMMENT '用户来源',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime(3) NOT NULL ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '最后修改时间',
  `deleted_by` bigint DEFAULT NULL COMMENT '删除人',
  `deleted_at` bigint NOT NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_username` (`username`,`deleted_at`) USING BTREE,
  UNIQUE KEY `uk_phone` (`phone`,`deleted_at`) USING BTREE,
  UNIQUE KEY `uk_email` (`email`,`deleted_at`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='用户';

