-- ----------------------------
-- Table structure for mdo_event_push_log
-- ----------------------------
DROP TABLE IF EXISTS `mdo_event_push_log`;
CREATE TABLE `mdo_event_push_log` (
  `id` bigint NOT NULL COMMENT '主键',
  `event_push_id` bigint NOT NULL COMMENT '所属推送',
  `request_time` datetime(3) DEFAULT NULL COMMENT '请求时间',
  `request_data` longtext COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `response_data` longtext COLLATE utf8mb4_general_ci COMMENT '响应内容',
  `response_time` datetime(3) DEFAULT NULL COMMENT '响应时间',
  `exec_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '状态\n[1-执行成功 2-执行失败]',
  `error_msg` longtext COLLATE utf8mb4_general_ci COMMENT '失败原因',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='事件推送日志';

-- ----------------------------
-- Records of mdo_event_push_log
-- ----------------------------
BEGIN;
COMMIT;

