-- ----------------------------
-- Table structure for mdo_event_type
-- ----------------------------
DROP TABLE IF EXISTS `mdo_event_type`;
CREATE TABLE `mdo_event_type` (
  `id` bigint NOT NULL COMMENT '主键',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '事件编码',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '事件名称',
  `remarks` varchar(512) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '事件描述',
  `weight` int DEFAULT NULL COMMENT '排序',
  `state` bit(1) DEFAULT b'1' COMMENT '状态',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_code` (`code`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='事件类型';

